using Microsoft.AspNetCore.Http;
using System.IdentityModel.Tokens.Jwt;

namespace MyApp.Middleware
{
    public class JwtAuthenticationMiddleware : IMiddleware
    {
        private readonly IConfiguration _configuration;

        public JwtAuthenticationMiddleware(IConfiguration configuration)
        {
            _configuration = configuration;
        }

        public async Task InvokeAsync(HttpContext context, Func<Task> next)
        {
            var token = context.Request.Headers["Authorization"].ToString();

            if (token != null)
            {
                var jwtSecurityTokenHandler = new JwtSecurityTokenHandler();
                var securityKey = _configuration["JWT:Secret"];
                var validationParameters = new TokenValidationParameters()
                {
                    IssuerSigningKey = securityKey,
                    ValidAudience = _configuration["JWT:Audience"],
                    ValidIssuer = _configuration["JWT:Issuer"]
                };

                var claimsPrincipal = jwtSecurityTokenHandler.ValidateToken(token, validationParameters);
                context.User = claimsPrincipal;
            }

            await next();
        }
    }
}